'use client';

import { useState } from 'react';
import Link from 'next/link';
import Image from 'next/image';
import { AnimatePresence, motion, useReducedMotion } from 'framer-motion';
import { services } from '@/lib/data/services';
import { ScrollReveal } from '@/components/ui/ScrollReveal';

export function ServicesSection() {
  const [active, setActive] = useState<string | null>(null);
  const pfx = useReducedMotion();

  return (
    <section
      className="bg-[#0a0a0a] section-pad border-t border-white/[0.05]"
      aria-labelledby="services-heading"
    >
      <div className="container-site">

        {/* Section label */}
        <ScrollReveal>
          <div className="flex items-center justify-between mb-20 md:mb-28">
            <div className="flex items-center gap-4">
              <span className="w-4 h-px bg-[#0000FF]" />
              <span
                className="font-body font-light uppercase text-[var(--color-cream)]/40"
                style={{ fontSize: '0.62rem', letterSpacing: '0.35em' }}
              >
                What We Do
              </span>
            </div>
            <Link
              href="/services"
              className="hidden md:flex items-center gap-3 font-body font-light uppercase text-[var(--color-cream)]/35 hover:text-[var(--color-cream)] transition-colors duration-400"
              id="services-heading"
              style={{ fontSize: '0.62rem', letterSpacing: '0.3em' }}
            >
              All Services <span className="w-6 h-px bg-current inline-block" />
            </Link>
          </div>
        </ScrollReveal>

        {/* List */}
        <div>
          {services.map((service, i) => {
            const on = active === service.slug;
            return (
              <ScrollReveal key={service.slug} delay={Math.min(i * 0.04, 0.2)}>
                <Link
                  href={`/services/${service.slug}`}
                  className="group block border-t border-white/[0.06] hover:border-white/20 transition-colors duration-500"
                  onMouseEnter={() => setActive(service.slug)}
                  onMouseLeave={() => setActive(null)}
                >
                  <div className="flex items-center gap-6 md:gap-10 py-8 md:py-10">

                    {/* Number */}
                    <span
                      className="shrink-0 font-body font-light text-[var(--color-cream)]/20 tabular-nums w-8"
                      style={{ fontSize: '0.7rem', letterSpacing: '0.1em' }}
                    >
                      {String(i + 1).padStart(2, '0')}
                    </span>

                    {/* Title + expand */}
                    <div className="flex-1 min-w-0">
                      <span
                        className="block font-display font-semibold uppercase transition-colors duration-300"
                        style={{
                          fontSize:      'clamp(1.5rem, 3.2vw, 3.2rem)',
                          lineHeight:    0.92,
                          letterSpacing: '-0.02em',
                          color:          on ? 'var(--color-cream)' : 'rgba(239,239,239,0.55)',
                        }}
                      >
                        {service.shortTitle}
                      </span>

                      <AnimatePresence>
                        {on && (
                          <motion.div
                            initial={pfx ? {} : { height: 0, opacity: 0 }}
                            animate={{ height: 'auto', opacity: 1 }}
                            exit={pfx ? {} : { height: 0, opacity: 0 }}
                            transition={{ duration: 0.3, ease: [0.25, 0.46, 0.45, 0.94] }}
                            className="overflow-hidden"
                          >
                            <p
                              className="font-body font-light text-[var(--color-cream)]/40 mt-3 max-w-xl leading-relaxed"
                              style={{ fontSize: '0.82rem' }}
                            >
                              {service.tagline}
                            </p>
                          </motion.div>
                        )}
                      </AnimatePresence>
                    </div>

                    {/* Thumbnail — fades in on hover */}
                    <AnimatePresence>
                      {on && !pfx && (
                        <motion.div
                          initial={{ opacity: 0, y: 6 }}
                          animate={{ opacity: 1, y: 0 }}
                          exit={{ opacity: 0, y: 6 }}
                          transition={{ duration: 0.3 }}
                          className="hidden lg:block shrink-0 relative overflow-hidden"
                          style={{ width: 100, height: 70 }}
                        >
                          <Image
                            src={service.image}
                            alt=""
                            fill
                            className="object-cover grayscale opacity-60"
                            sizes="100px"
                          />
                        </motion.div>
                      )}
                    </AnimatePresence>

                    {/* Arrow */}
                    <motion.span
                      className="shrink-0 font-body font-light text-[var(--color-cream)]/25 group-hover:text-[#0000FF] transition-colors duration-300"
                      animate={!pfx ? { x: on ? 4 : 0 } : {}}
                      transition={{ duration: 0.2 }}
                      style={{ fontSize: '0.85rem' }}
                    >
                      ↗
                    </motion.span>
                  </div>
                </Link>
              </ScrollReveal>
            );
          })}
          <div className="border-t border-white/[0.06]" />
        </div>
      </div>
    </section>
  );
}
